package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;
  private Excluder mockExcluder;

  @BeforeEach
  public void setUp() throws Exception {
    gsonBuilder = new GsonBuilder();

    // Use reflection to replace the private final Excluder excluder field with a mock
    mockExcluder = mock(Excluder.class);
    Field excluderField = GsonBuilder.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    excluderField.set(gsonBuilder, mockExcluder);
  }

  @Test
  public void testSetVersion_validVersion_callsWithVersionAndReturnsThis() {
    double version = 1.5;
    Excluder returnedExcluder = mock(Excluder.class);
    when(mockExcluder.withVersion(version)).thenReturn(returnedExcluder);

    GsonBuilder result = gsonBuilder.setVersion(version);

    assertSame(gsonBuilder, result);
    // Verify the excluder field was updated to returnedExcluder
    try {
      Field excluderField = GsonBuilder.class.getDeclaredField("excluder");
      excluderField.setAccessible(true);
      Object excluderValue = excluderField.get(gsonBuilder);
      assertSame(returnedExcluder, excluderValue);
    } catch (NoSuchFieldException | IllegalAccessException e) {
      fail("Reflection failed: " + e.getMessage());
    }
    verify(mockExcluder).withVersion(version);
  }

  @Test
  public void testSetVersion_zeroVersion_callsWithVersionAndReturnsThis() {
    double version = 0.0;
    Excluder returnedExcluder = mock(Excluder.class);
    when(mockExcluder.withVersion(version)).thenReturn(returnedExcluder);

    GsonBuilder result = gsonBuilder.setVersion(version);

    assertSame(gsonBuilder, result);
    try {
      Field excluderField = GsonBuilder.class.getDeclaredField("excluder");
      excluderField.setAccessible(true);
      Object excluderValue = excluderField.get(gsonBuilder);
      assertSame(returnedExcluder, excluderValue);
    } catch (NoSuchFieldException | IllegalAccessException e) {
      fail("Reflection failed: " + e.getMessage());
    }
    verify(mockExcluder).withVersion(version);
  }

  @Test
  public void testSetVersion_nan_throwsIllegalArgumentException() {
    double version = Double.NaN;

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
      gsonBuilder.setVersion(version);
    });
    assertEquals("Invalid version: " + version, thrown.getMessage());
    verifyNoInteractions(mockExcluder);
  }

  @Test
  public void testSetVersion_negativeVersion_throwsIllegalArgumentException() {
    double version = -0.1;

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
      gsonBuilder.setVersion(version);
    });
    assertEquals("Invalid version: " + version, thrown.getMessage());
    verifyNoInteractions(mockExcluder);
  }
}
